package com.futurewatch.truthorlietv

import android.content.Intent
import android.os.Bundle
import android.os.CountDownTimer
import android.view.KeyEvent
import android.view.View
import android.widget.FrameLayout
import android.widget.LinearLayout
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class VotingActivity : AppCompatActivity() {

    private lateinit var tvStatement: TextView
    private lateinit var tvTimer: TextView
    private lateinit var tvRound: TextView
    private lateinit var tvPlayer: TextView
    private lateinit var btnPause: android.widget.Button

    private lateinit var barTimer: View
    private lateinit var barTruth: View
    private lateinit var barLie: View
    private lateinit var frameTruth: FrameLayout
    private lateinit var frameLie: FrameLayout

    private var selectedAnswer: Boolean? = null
    private var isLocked = false
    private var currentStatement: String = ""

    private val totalTime = 20000L
    private lateinit var timer: CountDownTimer

    private var correctAnswer = false

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.voting)

        //
        tvStatement = findViewById(R.id.tvStatement)
        tvTimer = findViewById(R.id.tvTimer)
        tvRound = findViewById(R.id.tvRound)
        tvPlayer = findViewById(R.id.tvPlayer)
        btnPause = findViewById(R.id.btnPause)

        barTimer = findViewById(R.id.barTimer)
        barTruth = findViewById(R.id.barTruth)
        barLie = findViewById(R.id.barLie)
        frameTruth = findViewById(R.id.frameTruth)
        frameLie = findViewById(R.id.frameLie)

        //  Data
        currentStatement = intent.getStringExtra("STATEMENT") ?: ""
        correctAnswer = intent.getBooleanExtra("ANSWER", false)

        val actualRound = GameSession.getActualRound()
        val totalRounds = GameSession.totalRounds
        val currentPlayer = GameSession.getCurrentPlayer()

        tvStatement.text = currentStatement
        tvRound.text = "ROUND $actualRound/$totalRounds"
        tvPlayer.text = "${currentPlayer.name}, what do you think?"

        startTimer()
    }

    //  TIMER
    private fun startTimer() {

        timer = object : CountDownTimer(totalTime, 100) {
            override fun onTick(millisUntilFinished: Long) {

                val seconds = (millisUntilFinished / 1000).toInt()
                tvTimer.text = "${seconds}s"

                val progress = millisUntilFinished.toFloat() / totalTime
                barTimer.scaleX = progress
            }

            override fun onFinish() {
                if (!isLocked) {
                    // If no answer selected, auto-select random one
                    if (selectedAnswer == null) {
                        selectedAnswer = Math.random() > 0.5
                        selectAnswer(selectedAnswer!!)
                    }
                    lockAnswer()
                }
            }
        }

        timer.start()
    }

    override fun onKeyDown(keyCode: Int, event: KeyEvent?): Boolean {

        if (isLocked) return true

        when (keyCode) {
            KeyEvent.KEYCODE_DPAD_LEFT -> {
                selectAnswer(true)
                return true
            }
            KeyEvent.KEYCODE_DPAD_RIGHT -> {
                selectAnswer(false)
                return true
            }
            KeyEvent.KEYCODE_DPAD_CENTER, KeyEvent.KEYCODE_ENTER -> {
                // Only lock answer if an option has been selected
                if (selectedAnswer != null) {
                    lockAnswer()
                }
                return true
            }
        }

        return super.onKeyDown(keyCode, event)
    }

    //  Select Answer (only updates visual, does NOT lock)
    private fun selectAnswer(answer: Boolean) {
        selectedAnswer = answer

        val truthParams = frameTruth.layoutParams as LinearLayout.LayoutParams
        val lieParams = frameLie.layoutParams as LinearLayout.LayoutParams

        if (answer) {
            // TRUTH selected: covers 3/4
            truthParams.weight = 0.75f
            lieParams.weight = 0.25f
        } else {
            // LIE selected: covers 3/4
            lieParams.weight = 0.75f
            truthParams.weight = 0.25f
        }

        frameTruth.layoutParams = truthParams
        frameLie.layoutParams = lieParams
    }

    private fun lockAnswer() {
        isLocked = true
        timer.cancel()

        val currentPlayer = GameSession.getCurrentPlayer()
        val isCorrect = selectedAnswer == correctAnswer

        if (isCorrect) {
            currentPlayer.score += 100
        }

        // Store this player's answer for tracking
        currentPlayer.lastAnswer = selectedAnswer

        // Check if all players have voted in this round
        val totalPlayers = GameSession.players.size
        val nextPlayerTurn = GameSession.currPlayerTurn + 1
        val isLastPlayerInRound = (nextPlayerTurn % totalPlayers == 0)

        if (isLastPlayerInRound) {
            // All players voted for this round, show results
            val currentRound = GameSession.getActualRound()

            if (currentRound >= GameSession.totalRounds) {
                // Last round completed, show final results
                GameSession.currPlayerTurn = nextPlayerTurn
                val intent = Intent(this, ResultsActivity::class.java)
                intent.putExtra("STATEMENT", currentStatement)
                intent.putExtra("ANSWER", correctAnswer)
                intent.putExtra("IS_FINAL", true)
                startActivity(intent)
                finish()
            } else {
                // Show results for this round, then continue
                GameSession.currPlayerTurn = nextPlayerTurn
                val intent = Intent(this, ResultsActivity::class.java)
                intent.putExtra("STATEMENT", currentStatement)
                intent.putExtra("ANSWER", correctAnswer)
                intent.putExtra("IS_FINAL", false)
                startActivity(intent)
                finish()
            }
        } else {
            // More players to vote this round
            GameSession.currPlayerTurn = nextPlayerTurn
            val intent = Intent(this, VotingActivity::class.java)
            intent.putExtra("STATEMENT", currentStatement)
            intent.putExtra("ANSWER", correctAnswer)
            startActivity(intent)
            finish()
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        if (::timer.isInitialized) timer.cancel()
    }
}

